// Broker market-report landing pages. Add/remove sources here — each one
// becomes a separate Firecrawl Agent call so credit usage is explicit and
// a single bad page can't poison the whole batch.
const sources = [
  { broker: 'CRE Consultants',                url: 'https://www.creconsultants.com/research/' },
  { broker: 'LSI Companies',                  url: 'https://lsicompanies.com/market-reports/' },
  { broker: 'Investment Properties Corp',     url: 'https://ipcswfl.com/research/' },
  { broker: 'SVN Commercial Partners SWFL',   url: 'https://svnswfl.com/market-reports' }
];
return sources.map(s => ({ json: s }));

parameters.jsonBody:
={
  "urls": ["{{ $json.url }}"],
  "strictConstrainToURLs": true,
  "prompt": "Extract per-corridor broker positioning for Southwest Florida commercial real estate. For each corridor named in the report, return: corridor_name (exactly as the broker names it), market_positioning (the broker's framing of where this corridor sits in the market today, 1-3 sentences), dominant_tenant_types (1 short clause), development_pipeline_notes (any active development, deliveries, or expirations mentioned). Quarter should be the reporting quarter formatted YYYY-QN. Use null for any field the report does not cover — never invent.",
  "schema": {
    "type": "object",
    "properties": {
      "rows": {
        "type": "array",
        "items": {
          "type": "object",
          "required": ["corridor_name", "quarter"],
          "properties": {
            "corridor_name":              { "type": "string" },
            "quarter":                    { "type": "string", "pattern": "^\\d{4}-Q[1-4]$" },
            "market_positioning":         { "type": ["string", "null"] },
            "dominant_tenant_types":      { "type": ["string", "null"] },
            "development_pipeline_notes": { "type": ["string", "null"] }
          }
        }
      }
    }
  },
  "model": "spark-1-mini",
  "maxCredits": 750
}

