// Alias table maps broker shorthand → canonical corridor_profiles.corridor_name.
// Per the firecrawl-pipeline-skeleton plan, the canonical alias table lives
// alongside the corridor pipeline; this is the embedded starter copy. KEEP
// IN SYNC with the corridor pipeline's alias table — when you add a corridor
// alias there, mirror it here, or the broker narrative will silently drop.
const ALIASES = {
  // exact name → canonical
  "Immokalee Road":                       "Immokalee Rd North Naples",
  "Immokalee Rd":                         "Immokalee Rd North Naples",
  "US-41 / Cleveland":                    "US-41 / Cleveland Ave Fort Myers",
  "US 41 Cleveland":                      "US-41 / Cleveland Ave Fort Myers",
  "Tamiami Trail North Naples":           "Airport-Pulling North Naples",
  "Tamiami Trail Naples":                 "Airport-Pulling Naples",
  "Daniels Pkwy":                         "Daniels Parkway Fort Myers",
  "Daniels Parkway":                      "Daniels Parkway Fort Myers"
  // Add more aliases as the broker corpus expands.
};
function normalize(name) {
  if (!name) return null;
  const trimmed = String(name).trim();
  return ALIASES[trimmed] ?? trimmed;
}
const out = [];
for (const item of items) {
  const sourceUrl = item.json?.url ?? null;
  const broker    = item.json?.broker ?? null;
  const root      = item.json?.data?.result ?? item.json?.result ?? item.json;
  const rows      = Array.isArray(root?.rows) ? root.rows : [];
  for (const r of rows) {
    const canonical = normalize(r.corridor_name);
    if (!canonical) continue;
    out.push({
      json: {
        corridor_name_canonical: canonical,
        corridor_name_raw:       r.corridor_name,
        source_url:              sourceUrl,
        source_broker:           broker,
        narrative: {
          quarter:                    r.quarter,
          market_positioning:         r.market_positioning ?? null,
          dominant_tenant_types:      r.dominant_tenant_types ?? null,
          development_pipeline_notes: r.development_pipeline_notes ?? null
        }
      }
    });
  }
}
if (out.length === 0) {
  throw new Error('Flow 3: Firecrawl Agent returned zero rows across all broker pages — investigate before silently passing.');
}
return out;

// Postgres UPDATE returns the matched corridor_name; if a row didn't match,
// the previous node emitted an empty result. Log unmatched corridors so the
// alias table can be grown next quarter — but DON'T throw, partial coverage
// is the steady state.
const out = [];
for (const item of items) {
  const updated = item.json?.corridor_name;
  if (updated) {
    out.push({ json: { status: 'updated', corridor_name: updated } });
  } else {
    out.push({ json: { status: 'unmatched', raw: item.json } });
  }
}
return out;
